+// =============================================================================
+// Streaming Inference Context (Heterogeneous CPU+GPU Pipeline)
+// =============================================================================
+
+/// Streaming inference context using Zell's heterogeneous CPU+GPU pipeline
+/// This is the main inference engine that replaces llama.cpp Model.load()
+///
+/// Architecture:
+/// - Uses Q2_K compressed models (2.96 bpw, ~10GB for 32B models)
+/// - All layers fit in RAM (no SSD streaming needed)
+/// - CPU dequantizes Q2_K → BF16 while GPU computes in parallel
+/// - Zero-copy unified memory (Apple Silicon advantage)
+///
+/// Usage:
+///   var ctx = try StreamingContext.init(allocator, "model.gguf", profile);
+///   defer ctx.deinit();
+///   try ctx.generate(prompt, .{ .max_tokens = 256 });
+pub const StreamingContext = struct {
+    allocator: std.mem.Allocator,
+    loader: *gguf_loader.GGUFLoader,
+    engine: *streaming_qwen.StreamingEngine,
+    model_path_owned: []u8, // Owned copy for error messages
+
+    const Self = @This();
+
+    /// Initialize streaming context with Q2_K compressed model
+    /// Automatically uses requantized cache if available
+    pub fn init(
+        allocator: std.mem.Allocator,
+        model_path: []const u8,
+        requantized_path: ?[]const u8,
+    ) !*Self {
+        std.debug.print("\n🚀 Initializing Zell Streaming Inference Engine\n", .{});
+        std.debug.print("   Model: {s}\n", .{model_path});
+
+        // Determine which model file to load (requantized Q2_K cache or original)
+        const actual_path = requantized_path orelse model_path;
+        std.debug.print("   Loading: {s}\n", .{actual_path});
+
+        // 1. Initialize GGUF loader
+        var loader = try gguf_loader.GGUFLoader.init(allocator, actual_path);
+        errdefer loader.deinit();
+
+        // 2. Initialize streaming engine in Q2_K mode
+        var engine = try streaming_qwen.StreamingEngine.initQ2K(allocator, loader);
+        errdefer engine.deinit();
+
+        // 3. Load ALL layers into heap (Q2_K compression makes this possible!)
+        // For 32B model: 64 layers × 160MB = ~10GB (fits comfortably in 16GB RAM)
+        const n_layers = engine.config.n_layers;
+        std.debug.print("   Loading all {} layers into heap...\n", .{n_layers});
+        try engine.warmResidentLayers(n_layers);
+
+        std.debug.print("   ✅ All layers resident in RAM (zero SSD access!)\n\n", .{});
+
+        const self = try allocator.create(Self);
+        self.* = Self{
+            .allocator = allocator,
+            .loader = loader,
+            .engine = engine,
+            .model_path_owned = try allocator.dupe(u8, model_path),
+        };
+
+        return self;
+    }
+
+    pub fn deinit(self: *Self) void {
+        self.engine.deinit();
+        self.loader.deinit();
+        self.allocator.free(self.model_path_owned);
+        self.allocator.destroy(self);
+    }
+
+    /// Generate text using streaming inference
+    /// This is a placeholder - actual generation logic will be implemented in Phase 2.3
+    pub fn generate(
+        self: *Self,
+        prompt: []const u8,
+        opts: GenerateOptions,
+    ) !void {
+        _ = self;
+        _ = prompt;
+        _ = opts;
+
+        std.debug.print("🚧 StreamingContext.generate() not yet implemented\n", .{});
+        std.debug.print("   This will be completed in Phase 2.3\n", .{});
+        std.debug.print("   For now, this demonstrates the streaming engine is loaded and ready\n", .{});
+
+        // TODO Phase 2.3: Implement actual generation loop
+        // 1. Tokenize prompt
+        // 2. Process each layer using engine.compute()
+        // 3. Sample next token
+        // 4. Call opts.on_token() callback
+        // 5. Repeat until max_tokens or EOS
+
+        return error.NotImplemented;
+    }
+};
